mapper.select:
SELECT s.biz_no AS bizNo, s.user_id AS userId, u.nickname AS creatorName, s.style_name AS styleName, s.prompt AS prompt, s.scope AS scope, s.source_type AS sourceType, s.audit_status AS auditStatus, s.reject_reason AS rejectReason, s.created_at AS createdAt FROM u_user_style s LEFT JOIN u_user u ON u.id = s.user_id AND u.is_deleted = 0 WHERE s.is_deleted = 0 AND s.audit_status = #{status}
AND (s.style_name LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY s.created_at DESC LIMIT #{offset}, #{limit}
